# Plan: Extract Service Layer from Express Route Handlers

## Context

`src/routes/products.ts` and `src/routes/orders.ts` currently mix HTTP concerns (parsing
params, sending responses) with business logic (filtering, aggregation, validation, state
machines, inventory mutation). This makes unit-testing the logic impossible without
spinning up an HTTP server, and makes the routes hard to maintain as logic grows.

The goal is to extract all business logic into two service modules so that:
- Route handlers only parse HTTP input and send HTTP responses
- Service functions are pure (or data-coupled) TypeScript that can be tested independently
- All existing Vitest/Supertest tests continue to pass unchanged

---

## Project Snapshot

| File | Role | Changes? |
|------|------|----------|
| `src/app.ts` | Express setup, mounts routers | ❌ None |
| `src/types.ts` | Shared TS interfaces | ✅ Add `ServiceError` class |
| `src/data.ts` | In-memory arrays + `getNextOrderId()` | ❌ None |
| `src/routes/products.ts` | Product route handlers | ✅ Delegate to service |
| `src/routes/orders.ts` | Order route handlers | ✅ Delegate to service |
| `src/services/product-service.ts` | **NEW** product business logic | ✅ Create |
| `src/services/order-service.ts` | **NEW** order business logic | ✅ Create |
| `tests/products.test.ts` | HTTP-level tests via supertest | ❌ None |
| `tests/orders.test.ts` | HTTP-level tests via supertest | ❌ None |

---

## Error Strategy

Add a `ServiceError` class to `src/types.ts`. Service functions throw it for any domain
error (400 or 404). Route handlers use a single try/catch pattern to translate thrown
errors into HTTP responses.

```
Route → calls service → service throws ServiceError(statusCode, message)
Route → catches → res.status(statusCode).json({ error: message })
```

---

## Step-by-Step Implementation

### Step 1 — Add `ServiceError` to `src/types.ts`

Append to the end of the existing file:

```typescript
export class ServiceError extends Error {
  constructor(public readonly statusCode: number, message: string) {
    super(message);
    this.name = "ServiceError";
  }
}
```

---

### Step 2 — Create `src/services/product-service.ts`

**New file.** Contains all product business logic extracted from the route handlers.

```typescript
import { products } from "../data.js";
import type { Product } from "../types.js";
import { ServiceError } from "../types.js";

// ── Return types ──────────────────────────────────────────────────────────────

export interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductSummary {
  count: number;
  totalInventoryValue: number;
  averagePrice: number;
}

export interface ProductListResult {
  products: Product[];
  summary: ProductSummary;
}

export interface ProductDetail extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function toProductDetail(product: Product): ProductDetail {
  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

// ── Service functions ─────────────────────────────────────────────────────────

/**
 * Returns all products matching the given filters, plus summary statistics.
 * Never throws — returns an empty list if no products match.
 */
export function listProducts(filters: ProductFilters): ProductListResult {
  let filtered = [...products];

  if (filters.category !== undefined) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }
  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }
  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

/**
 * Returns a single product with computed fields.
 * Throws ServiceError(404) if not found.
 */
export function getProductById(id: number): ProductDetail {
  const product = products.find((p) => p.id === id);
  if (!product) {
    throw new ServiceError(404, "Product not found");
  }
  return toProductDetail(product);
}

/**
 * Adjusts a product's stock by the given amount.
 * Throws ServiceError(404) if not found.
 * Throws ServiceError(400) if the resulting stock would be negative.
 */
export function adjustProductStock(
  id: number,
  adjustment: number
): ProductDetail {
  const product = products.find((p) => p.id === id);
  if (!product) {
    throw new ServiceError(404, "Product not found");
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    throw new ServiceError(400, "Insufficient stock");
  }

  product.stock = newStock;
  return toProductDetail(product);
}
```

---

### Step 3 — Create `src/services/order-service.ts`

**New file.** Contains all order business logic extracted from the route handlers.

```typescript
import { orders, products, getNextOrderId } from "../data.js";
import type { Order, OrderItem, CreateOrderInput } from "../types.js";
import { ServiceError } from "../types.js";

// ── Return types ──────────────────────────────────────────────────────────────

export interface OrderFilters {
  userId?: number;
  status?: string;
}

export interface OrderSummary {
  count: number;
  totalRevenue: number;
}

export interface OrderListResult {
  orders: Order[];
  summary: OrderSummary;
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"] as const;
type OrderStatus = (typeof VALID_STATUSES)[number];

const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

// ── Service functions ─────────────────────────────────────────────────────────

/**
 * Returns all orders matching the given filters, plus summary statistics.
 * Never throws — returns an empty list if no orders match.
 */
export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }
  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

/**
 * Returns a single order with items enriched by product name.
 * Throws ServiceError(404) if not found.
 */
export function getOrderById(id: number): EnrichedOrder {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new ServiceError(404, "Order not found");
  }

  const enrichedItems: EnrichedOrderItem[] = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return { ...item, productName: product?.name ?? "Unknown" };
  });

  return { ...order, items: enrichedItems };
}

/**
 * Validates input, checks stock, deducts inventory, and creates a new order.
 * Throws ServiceError(400) for any validation failure.
 */
export function createOrder(input: CreateOrderInput): Order {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new ServiceError(400, "userId and items are required");
  }
  if (input.items.length === 0) {
    throw new ServiceError(400, "Order must have at least one item");
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new ServiceError(400, `Product ${item.productId} not found`);
    }
    if (item.quantity <= 0) {
      throw new ServiceError(400, "Quantity must be positive");
    }
    if (product.stock < item.quantity) {
      throw new ServiceError(400, `Insufficient stock for ${product.name}`);
    }

    product.stock -= item.quantity;

    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += product.price * item.quantity;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);
  return order;
}

/**
 * Transitions an order to a new status, enforcing the allowed state machine.
 * Throws ServiceError(404) if order not found.
 * Throws ServiceError(400) for invalid or disallowed status values.
 */
export function updateOrderStatus(id: number, status: string): Order {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new ServiceError(404, "Order not found");
  }

  if (!VALID_STATUSES.includes(status as OrderStatus)) {
    throw new ServiceError(
      400,
      `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`
    );
  }

  const typedStatus = status as OrderStatus;
  if (!STATUS_TRANSITIONS[order.status]?.includes(typedStatus)) {
    throw new ServiceError(
      400,
      `Cannot transition from ${order.status} to ${status}`
    );
  }

  order.status = typedStatus;
  return order;
}
```

---

### Step 4 — Refactor `src/routes/products.ts`

Replace the entire file. All business logic is removed; handlers only parse HTTP input,
call services, and send responses.

```typescript
import { Router } from "express";
import {
  listProducts,
  getProductById,
  adjustProductStock,
} from "../services/product-service.js";
import { ServiceError } from "../types.js";

const router = Router();

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const result = listProducts({
    category: typeof category === "string" ? category : undefined,
    minPrice:
      typeof minPrice === "string" && !isNaN(parseFloat(minPrice))
        ? parseFloat(minPrice)
        : undefined,
    maxPrice:
      typeof maxPrice === "string" && !isNaN(parseFloat(maxPrice))
        ? parseFloat(maxPrice)
        : undefined,
  });

  res.json(result);
});

router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  try {
    res.json(getProductById(id));
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
      return;
    }
    throw err;
  }
});

router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: number };

  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  try {
    res.json(adjustProductStock(id, adjustment));
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
      return;
    }
    throw err;
  }
});

export { router as productRouter };
```

