### Step 2 — Create `src/services/product-service.ts`

**New file.** Contains all product business logic extracted from the route handlers.

```typescript
import { products } from "../data.js";
import type { Product } from "../types.js";
import { ServiceError } from "../types.js";

// ── Return types ──────────────────────────────────────────────────────────────

export interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductSummary {
  count: number;
  totalInventoryValue: number;
  averagePrice: number;
}

export interface ProductListResult {
  products: Product[];
  summary: ProductSummary;
}

export interface ProductDetail extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function toProductDetail(product: Product): ProductDetail {
  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

// ── Service functions ─────────────────────────────────────────────────────────

/**
 * Returns all products matching the given filters, plus summary statistics.
 * Never throws — returns an empty list if no products match.
 */
export function listProducts(filters: ProductFilters): ProductListResult {
  let filtered = [...products];

  if (filters.category !== undefined) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }
  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }
  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

/**
 * Returns a single product with computed fields.
 * Throws ServiceError(404) if not found.
 */
export function getProductById(id: number): ProductDetail {
  const product = products.find((p) => p.id === id);
  if (!product) {
    throw new ServiceError(404, "Product not found");
  }
  return toProductDetail(product);
}

/**
 * Adjusts a product's stock by the given amount.
 * Throws ServiceError(404) if not found.
 * Throws ServiceError(400) if the resulting stock would be negative.
 */
export function adjustProductStock(
  id: number,
  adjustment: number
): ProductDetail {
  const product = products.find((p) => p.id === id);
  if (!product) {
    throw new ServiceError(404, "Product not found");
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    throw new ServiceError(400, "Insufficient stock");
  }

  product.stock = newStock;
  return toProductDetail(product);
}
```

